import{_ as r}from"./chunks/wallet.7Yk7pML4.js";import{_ as a,o as e,c as o,a2 as s}from"./chunks/framework.BflysNKA.js";const _=JSON.parse('{"title":"充值","description":"","frontmatter":{},"headers":[],"relativePath":"guide/recharge.md","filePath":"guide/recharge.md","lastUpdated":1780487298000}'),n={name:"guide/recharge.md"};function i(l,t,d,g,h,p){return e(),o("div",null,[...t[0]||(t[0]=[s('<h1 id="充值" tabindex="-1">充值 <a class="header-anchor" href="#充值" aria-label="Permalink to &quot;充值&quot;">​</a></h1><p>余额用于支付模型请求费用，<strong>余额为 0 时调用会失败</strong>。第一次接入建议先充小额（¥10 即可），跑通后再按用量充值。</p><h2 id="第-1-步-打开钱包页面" tabindex="-1">第 1 步：打开钱包页面 <a class="header-anchor" href="#第-1-步-打开钱包页面" aria-label="Permalink to &quot;第 1 步：打开钱包页面&quot;">​</a></h2><p>登录控制台后，点左侧导航栏的 <strong>钱包</strong>。页面上方是当前余额，中间的 <strong>添加资金</strong> 区域就是充值入口：</p><p><img src="'+r+'" alt="钱包充值：① 选充值金额、② 或填自定义金额、③ 选支付方式，订单历史在右上角"></p><h2 id="第-2-步-选择充值金额" tabindex="-1">第 2 步：选择充值金额 <a class="header-anchor" href="#第-2-步-选择充值金额" aria-label="Permalink to &quot;第 2 步：选择充值金额&quot;">​</a></h2><p>在 <strong>金额</strong> 区域点一个预设档位（¥10 / ¥20 / ¥50 / ¥100 / ¥200 / ¥500，图中 ①），或在 <strong>自定义金额</strong> 框里填其他数值（图中 ②，右侧会实时显示「待支付金额」）。</p><p>第一次接入只需要先充 <strong>¥10</strong> 把流程跑通，后续再按需充值。</p><h2 id="第-3-步-选择支付方式并支付" tabindex="-1">第 3 步：选择支付方式并支付 <a class="header-anchor" href="#第-3-步-选择支付方式并支付" aria-label="Permalink to &quot;第 3 步：选择支付方式并支付&quot;">​</a></h2><p>在 <strong>付款方式</strong> 选择 <strong>支付宝</strong> 或 <strong>微信</strong>（图中 ③），然后按页面提示完成支付（扫码或跳转支付）。</p><p>支付成功后余额<strong>即时到账</strong>，无需等待，回到钱包或概览页即可看到余额变化。</p><div class="tip custom-block"><p class="custom-block-title">有兑换码？</p><p>付款方式下方有「兑换码」输入框，填入兑换码后点 <strong>兑换额度</strong> 即可直接到账，无需走支付。</p></div><h2 id="充值后确认" tabindex="-1">充值后确认 <a class="header-anchor" href="#充值后确认" aria-label="Permalink to &quot;充值后确认&quot;">​</a></h2><table tabindex="0"><thead><tr><th>检查项</th><th>在哪看</th></tr></thead><tbody><tr><td>余额是否到账</td><td>钱包页顶部 <strong>当前余额</strong>，或概览页的余额卡片</td></tr><tr><td>这笔充值记录</td><td>钱包页右上角 <strong>订单历史</strong> 按钮</td></tr></tbody></table><p><strong>充了钱但余额没变？</strong> 先刷新页面，再点 <strong>订单历史</strong> 看有没有这笔记录：</p><ul><li>订单历史里<strong>有记录且已支付</strong> → 等几秒后刷新概览页；</li><li>订单历史里<strong>没有这笔</strong> → 说明支付没有真正完成，请重新发起。</li></ul><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>余额到账后：</p><ol><li><a href="/guide/create-key">创建专属 Key</a>（如果还没创建）</li><li>去 <a href="https://xiaolan1.cn/pricing" target="_blank" rel="noreferrer">模型广场</a> 点模型名复制</li><li>配置工具开始使用，详见 <a href="/guide/quick-start">快速接入</a></li></ol>',19)])])}const b=a(n,[["render",i]]);export{_ as __pageData,b as default};
